logger = logging.getLogger(__name__)

def seed_speeches(db: Session) -> None:
    logger.info("Speeches")

    existing_speeches = {
        title.lower()
        for (title,) in db.query(Speech.title).all()
    }

    for item in SPEECHES:
        formatted_title = item["title"].title()

        if formatted_title.lower() not in existing_speeches:
            speech = Speech(
                presence_id=item["presence_id"],
                title=item["title"],
                content=item["content"],
            )
            db.add(speech)